sql:
SELECT product_name
FROM products
WHERE product_id IN (SELECT product_id FROM access_logs);

SELECT * 
FROM product_variants 
WHERE product_id = 1;

SELECT products.product_name, marketing_authorization_holders.ma_holder_name
FROM products
JOIN marketing_authorization_holders ON products.ma_holder_id = marketing_authorization_holders.ma_holder_id;

SELECT user_name
FROM users
WHERE user_id = (SELECT last_updated_by FROM products WHERE product_id = 1);

